                  <td className="px-6 py-4 text-right text-sm text-warning">
                    ${mesero.propinas.toFixed(0)}
                  </td>
                  <td className="px-6 py-4 text-right text-sm font-bold text-gradient">
                    ${(mesero.ventas + mesero.propinas).toFixed(0)}
                  </td>
                </tr>
              ))}
